import React, { useState, useRef } from 'react';
import { motion } from 'framer-motion';
import Sidebar from '../../components/Sidebar';
import Navbar from '../../components/Navbar';
import axios from 'axios';
import toast from 'react-hot-toast';
import { FiPlus, FiTrash2, FiSend, FiUploadCloud } from 'react-icons/fi';

const API = 'http://localhost:5000/api';

const CreateExam = () => {
  const [examData, setExamData] = useState({
    title: '', description: '', subject: '', duration: 60,
    totalMarks: 0, startTime: '', endTime: '', batch: '', course: ''
  });
  const [questions, setQuestions] = useState([{
    question: '', options: [
      { text: '', isCorrect: true },
      { text: '', isCorrect: false },
      { text: '', isCorrect: false },
      { text: '', isCorrect: false }
    ], marks: 1
  }]);
  const [pdfFile, setPdfFile] = useState(null);
  const [loading, setLoading] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const fileRef = useRef();

  const handleExamChange = (e) => {
    setExamData({ ...examData, [e.target.name]: e.target.value });
  };

  const handleQuestionChange = (index, field, value) => {
    const updated = [...questions];
    updated[index][field] = value;
    setQuestions(updated);
  };

  const handleOptionChange = (qIndex, oIndex, value) => {
    const updated = [...questions];
    updated[qIndex].options[oIndex].text = value;
    setQuestions(updated);
  };

  const handleCorrectAnswer = (qIndex, oIndex) => {
    const updated = [...questions];
    updated[qIndex].options = updated[qIndex].options.map((opt, i) => ({
      ...opt, isCorrect: i === oIndex
    }));
    setQuestions(updated);
  };

  const addQuestion = () => {
    setQuestions([...questions, {
      question: '', options: [
        { text: '', isCorrect: true },
        { text: '', isCorrect: false },
        { text: '', isCorrect: false },
        { text: '', isCorrect: false }
      ], marks: 1
    }]);
  };

  const removeQuestion = (index) => {
    if (questions.length > 1) {
      setQuestions(questions.filter((_, i) => i !== index));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const totalMarks = questions.reduce((sum, q) => sum + Number(q.marks), 0);

    setLoading(true);
    try {
      const formData = new FormData();
      Object.keys(examData).forEach(key => {
        if (key !== 'totalMarks') formData.append(key, examData[key]);
      });
      formData.append('totalMarks', totalMarks);
      formData.append('questions', JSON.stringify(questions));
      if (pdfFile) formData.append('pdfFile', pdfFile);

      await axios.post(`${API}/exams`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });

      toast.success('Exam created successfully!');
      setExamData({ title: '', description: '', subject: '', duration: 60, totalMarks: 0, startTime: '', endTime: '', batch: '', course: '' });
      setQuestions([{ question: '', options: [{ text: '', isCorrect: true }, { text: '', isCorrect: false }, { text: '', isCorrect: false }, { text: '', isCorrect: false }], marks: 1 }]);
      setPdfFile(null);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to create exam');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="page-container">
      <Sidebar isOpen={isSidebarOpen} onClose={() => setIsSidebarOpen(false)} />
      <div className="main-content" style={{ paddingTop: '90px' }}>
        <Navbar onMenuToggle={(state) => setIsSidebarOpen(state)} />

        <motion.div className="page-header" initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }}>
          <h1>📝 Create Exam</h1>
          <p>Create MCQ-based exams for students</p>
        </motion.div>

        <motion.div className="card" style={{ maxWidth: '800px' }} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}>
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label className="form-label">Exam Title</label>
              <input type="text" name="title" className="form-input" placeholder="e.g., JavaScript MCQ Test"
                value={examData.title} onChange={handleExamChange} required />
            </div>

            <div className="form-group">
              <label className="form-label">Description</label>
              <textarea name="description" className="form-textarea" placeholder="Exam description..."
                value={examData.description} onChange={handleExamChange} />
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '15px' }}>
              <div className="form-group">
                <label className="form-label">Subject</label>
                <input type="text" name="subject" className="form-input" placeholder="Subject"
                  value={examData.subject} onChange={handleExamChange} required />
              </div>
              <div className="form-group">
                <label className="form-label">Duration (minutes)</label>
                <input type="number" name="duration" className="form-input"
                  value={examData.duration} onChange={handleExamChange} required />
              </div>
              <div className="form-group">
                <label className="form-label">Course</label>
                <select name="course" className="form-select" value={examData.course} onChange={handleExamChange}>
                  <option value="">All Courses</option>
                  <option value="Web Development">Web Development</option>
                  <option value="App Development">App Development</option>
                  <option value="Python Programming">Python Programming</option>
                </select>
              </div>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '15px' }}>
              <div className="form-group">
                <label className="form-label">Start Time</label>
                <input type="datetime-local" name="startTime" className="form-input"
                  value={examData.startTime} onChange={handleExamChange} required />
              </div>
              <div className="form-group">
                <label className="form-label">End Time</label>
                <input type="datetime-local" name="endTime" className="form-input"
                  value={examData.endTime} onChange={handleExamChange} required />
              </div>
              <div className="form-group">
                <label className="form-label">Batch</label>
                <input type="text" name="batch" className="form-input" placeholder="Batch"
                  value={examData.batch} onChange={handleExamChange} />
              </div>
            </div>

            {/* PDF Upload */}
            <div className="form-group">
              <label className="form-label">Upload Exam PDF (Optional)</label>
              <div className="upload-area" onClick={() => fileRef.current.click()} style={{ padding: '20px' }}>
                <FiUploadCloud style={{ fontSize: '2rem', color: 'var(--primary)' }} />
                <p style={{ marginTop: '8px' }}>{pdfFile ? pdfFile.name : 'Click to upload exam PDF'}</p>
              </div>
              <input type="file" ref={fileRef} style={{ display: 'none' }} accept=".pdf"
                onChange={(e) => setPdfFile(e.target.files[0])} />
            </div>

            {/* Questions */}
            <div style={{ borderTop: '1px solid rgba(102,126,234,0.15)', paddingTop: '20px', marginTop: '20px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
                <h3 style={{ fontFamily: 'Poppins' }}>Questions ({questions.length})</h3>
                <span className="badge badge-primary">
                  Total Marks: {questions.reduce((sum, q) => sum + Number(q.marks), 0)}
                </span>
              </div>

              {questions.map((q, qIndex) => (
                <motion.div
                  key={qIndex}
                  style={{
                    background: 'rgba(102,126,234,0.05)', border: '1px solid rgba(102,126,234,0.15)',
                    borderRadius: '14px', padding: '20px', marginBottom: '15px'
                  }}
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: qIndex * 0.05 }}
                >
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '12px' }}>
                    <span className="badge badge-primary">Question {qIndex + 1}</span>
                    <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                      <input type="number" className="form-input" style={{ width: '80px', padding: '6px 10px' }}
                        placeholder="Marks" value={q.marks}
                        onChange={(e) => handleQuestionChange(qIndex, 'marks', e.target.value)} min="1" />
                      {questions.length > 1 && (
                        <button type="button" className="btn btn-danger btn-sm" onClick={() => removeQuestion(qIndex)}>
                          <FiTrash2 />
                        </button>
                      )}
                    </div>
                  </div>

                  <div className="form-group">
                    <input type="text" className="form-input" placeholder="Enter question..."
                      value={q.question}
                      onChange={(e) => handleQuestionChange(qIndex, 'question', e.target.value)} required />
                  </div>

                  <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
                    {q.options.map((opt, oIndex) => (
                      <div key={oIndex} style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                        <input
                          type="radio"
                          name={`correct-${qIndex}`}
                          checked={opt.isCorrect}
                          onChange={() => handleCorrectAnswer(qIndex, oIndex)}
                          style={{ accentColor: 'var(--primary)' }}
                        />
                        <input type="text" className="form-input" style={{ padding: '8px 12px' }}
                          placeholder={`Option ${oIndex + 1}`}
                          value={opt.text}
                          onChange={(e) => handleOptionChange(qIndex, oIndex, e.target.value)} required />
                      </div>
                    ))}
                  </div>
                </motion.div>
              ))}

              <motion.button
                type="button" className="btn btn-outline btn-block"
                onClick={addQuestion}
                whileHover={{ scale: 1.02 }}
                style={{ marginBottom: '20px' }}
              >
                <FiPlus /> Add Question
              </motion.button>
            </div>

            <motion.button
              type="submit" className="btn btn-primary btn-block btn-lg"
              disabled={loading}
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
            >
              {loading ? 'Creating...' : <><FiSend /> Create Exam</>}
            </motion.button>
          </form>
        </motion.div>
      </div>
    </div>
  );
};

export default CreateExam;
